def values(self, *keys):
    """
    Restituisce i valori del record, con la possibilità di filtrare per includere solo determinati valori in base all'indice o alla chiave.

    :param keys: indici o chiavi degli elementi da includere; se non viene fornito nessun parametro, verranno inclusi tutti i valori  
    :return: lista di valori  
    :rtype: list
    """
    # Se non vengono fornite chiavi, restituisci tutti i valori
    if not keys:
        return list(self.__dict__.values())

    # Filtra i valori in base alle chiavi fornite
    valori_filtrati = []
    for chiave in keys:
        if chiave in self.__dict__:
            valori_filtrati.append(self.__dict__[chiave])
        elif isinstance(chiave, int) and 0 <= chiave < len(self.__dict__):
            # Se la chiave è un indice, ottieni il valore corrispondente
            valori_filtrati.append(list(self.__dict__.values())[chiave])

    return valori_filtrati

def cached(cache, key=hashkey, lock=None):
    """
    Decorator per racchiudere una funzione con un callable di memoizzazione che salva  
    i risultati in una cache.
    """
    def decoratore(funzione):
        def funzione_decorata(*args, **kwargs):
            # Genera la chiave per la cache
            chiave_cache = key(*args, **kwargs)

            # Controlla se il risultato è già in cache
            if lock:
                with lock:
                    if chiave_cache in cache:
                        return cache[chiave_cache]
            else:
                if chiave_cache in cache:
                    return cache[chiave_cache]

            # Se non è in cache, esegui la funzione e salva il risultato
            risultato = funzione(*args, **kwargs)

            if lock:
                with lock:
                    cache[chiave_cache] = risultato
            else:
                cache[chiave_cache] = risultato

            return risultato

        return funzione_decorata

    return decoratore

from functools import lru_cache as _lru_cache

def lru_cache(maxsize=128, typed=False):
    """
    Decorator per racchiudere una funzione con un oggetto callable che memorizza
    fino a `maxsize` risultati basandosi su un algoritmo Least Recently Used (LRU).
    """
    def decoratore(funzione):
        return _lru_cache(maxsize=maxsize, typed=typed)(funzione)
    return decoratore

def get(self, key, default=None):
    """
    Restituisce il valore associato alla chiave `key` se presente nel dizionario `D`, 
    altrimenti restituisce il valore predefinito `default`. Se `default` non è specificato, 
    il valore predefinito è `None`.
    """
    if key in self:
        return self[key]
    else:
        return default

