def is_fill_request_seq(seq):
    """
    Verifica se *seq* può essere convertito in un oggetto di tipo FillRequestSeq.

    Restituisce `True` solo se *seq* è un elemento di tipo FillRequest  
    o contiene almeno un elemento di questo tipo,  
    e non è una sequenza di tipo Source.
    """
    # Verifica se seq è un'istanza di FillRequest
    if isinstance(seq, FillRequest):
        return True

    # Verifica se seq è una sequenza e contiene almeno un elemento di tipo FillRequest
    if isinstance(seq, (list, tuple)):
        for elemento in seq:
            if isinstance(elemento, FillRequest):
                return True

    # Verifica se seq è una sequenza di tipo Source
    if isinstance(seq, Source):
        return False

    return False

def is_run_el(obj):
    """
    Controlla se l'oggetto contiene il metodo eseguibile 'run'.
    """
    # Verifica se l'oggetto ha l'attributo 'run' e se è un metodo chiamabile
    return hasattr(obj, 'run') and callable(getattr(obj, 'run'))

