def generate_default_observer_schema_dict(manifest_dict, first_level=False):
    """
    Insieme alla funzione :func:`generate_default_observer_schema_list`, questa funzione viene chiamata ricorsivamente per generare una parte dello schema predefinito `observer_schema` a partire da una risorsa Kubernetes, definita rispettivamente da `manifest_dict` o `manifest_list`.

    ### Argomenti:
    - **manifest_dict (dict)**: Risorse Kubernetes parziali.
    - **first_level (bool, opzionale)**: Se impostato su True, indica che il dizionario rappresenta l'intero schema `observer_schema` di una risorsa Kubernetes.

    ### Ritorna:
    - **dict**: Lo schema parziale `observer_schema` generato.

    Questa funzione crea un nuovo dizionario a partire da `manifest_dict` e sostituisce tutti i valori che non sono liste o dizionari con `None`.

    Nel caso di un dizionario `first_level` (ovvero lo schema completo `observer_schema` per una risorsa), i valori dei campi identificativi vengono copiati dal file manifest.
    """
    schema_dict = {}

    # Campi identificativi da copiare se siamo al primo livello
    campi_identificativi = ["apiVersion", "kind", "metadata"]

    for chiave, valore in manifest_dict.items():
        if isinstance(valore, dict):
            # Se il valore è un dizionario, chiamata ricorsiva
            schema_dict[chiave] = generate_default_observer_schema_dict(valore)
        elif isinstance(valore, list):
            # Se il valore è una lista, chiamata ricorsiva alla funzione per le liste
            schema_dict[chiave] = generate_default_observer_schema_list(valore)
        else:
            # Se non è né un dizionario né una lista, impostiamo il valore a None
            schema_dict[chiave] = None

    # Se siamo al primo livello, copiamo i campi identificativi
    if first_level:
        for campo in campi_identificativi:
            if campo in manifest_dict:
                schema_dict[campo] = manifest_dict[campo]

    return schema_dict

def generate_default_observer_schema_list(manifest_list):
    """
    Funzione ausiliaria per gestire le liste all'interno del dizionario.
    """
    schema_list = []

    for elemento in manifest_list:
        if isinstance(elemento, dict):
            schema_list.append(generate_default_observer_schema_dict(elemento))
        elif isinstance(elemento, list):
            schema_list.append(generate_default_observer_schema_list(elemento))
        else:
            schema_list.append(None)

    return schema_list

def update_last_applied_manifest_list_from_resp(
    last_applied_manifest, observer_schema, response
):
    """
    Aggiorna una lista parziale di `last_applied_manifest` basata su una risposta parziale di Kubernetes.

    Argomenti:
        last_applied_manifest (list): Lista parziale di `last_applied_manifest` da aggiornare.
        observer_schema (list): Schema parziale dell'osservatore.
        response (list): Risposta parziale dall'API di Kubernetes.
    """
    # Itera attraverso ogni elemento nello schema dell'osservatore
    for indice, campo_osservato in enumerate(observer_schema):
        # Se l'indice è fuori dai limiti di last_applied_manifest, aggiungi un nuovo elemento
        if indice >= len(last_applied_manifest):
            last_applied_manifest.append(None)

        # Se il campo osservato è un dizionario, chiama la funzione ricorsiva per i dizionari
        if isinstance(campo_osservato, dict):
            update_last_applied_manifest_dict_from_resp(
                last_applied_manifest[indice], campo_osservato, response[indice]
            )
        # Se il campo osservato è una lista, chiama questa funzione ricorsivamente
        elif isinstance(campo_osservato, list):
            update_last_applied_manifest_list_from_resp(
                last_applied_manifest[indice], campo_osservato, response[indice]
            )
        # Altrimenti, aggiorna direttamente il valore
        else:
            last_applied_manifest[indice] = response[indice]

def update_last_applied_manifest_dict_from_resp(
    last_applied_manifest, observer_schema, response
):
    """
    Aggiorna il dizionario `last_applied_manifest` con i valori dalla risposta di Kubernetes.

    Argomenti:
        last_applied_manifest (dict): Dizionario parziale da aggiornare.
        observer_schema (dict): Schema parziale che definisce i campi da osservare.
        response (dict): Risposta parziale dall'API di Kubernetes.

    Eccezioni:
        KeyError: Se un campo osservato non è presente nella risposta di Kubernetes.
    """
    for campo, schema in observer_schema.items():
        if campo not in response:
            raise KeyError(f"Il campo '{campo}' non è presente nella risposta di Kubernetes.")

        if isinstance(schema, dict):
            # Se il campo è un dizionario, aggiorna ricorsivamente
            if campo not in last_applied_manifest:
                last_applied_manifest[campo] = {}
            update_last_applied_manifest_dict_from_resp(
                last_applied_manifest[campo], schema, response[campo]
            )
        elif isinstance(schema, list):
            # Se il campo è una lista, chiama la funzione corrispondente per le liste
            if campo not in last_applied_manifest:
                last_applied_manifest[campo] = []
            update_last_applied_manifest_list_from_resp(
                last_applied_manifest[campo], schema, response[campo]
            )
        else:
            # Se il campo è un valore semplice, aggiorna direttamente
            last_applied_manifest[campo] = response[campo]

def generate_default_observer_schema(app):
    """
    Genera lo schema di osservazione predefinito per ogni risorsa Kubernetes presente in
    ``spec.manifest`` per la quale non è stato specificato uno schema di osservazione personalizzato.

    Argomenti:
        app (krake.data.kubernetes.Application): L'applicazione per la quale generare uno
            schema di osservazione predefinito.
    """
    # Ottieni i manifesti dall'applicazione
    manifesti = app.spec.manifest

    # Schema di osservazione predefinito
    schema_predefinito = {
        "type": "object",
        "properties": {
            "status": {
                "type": "object",
                "properties": {
                    "conditions": {
                        "type": "array",
                        "items": {
                            "type": "object",
                            "properties": {
                                "type": {"type": "string"},
                                "status": {"type": "string"},
                                "lastTransitionTime": {"type": "string"},
                                "reason": {"type": "string"},
                                "message": {"type": "string"}
                            }
                        }
                    }
                }
            }
        }
    }

    # Applica lo schema predefinito a ogni risorsa nel manifesto
    for risorsa in manifesti:
        if not hasattr(risorsa, 'observer_schema'):
            risorsa.observer_schema = schema_predefinito

    return app
